#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int minInsertions(string s) {
        int n = s.size();
        vector<vector<int>> dp(n, vector<int>(n, 0));
        for (int gap = 1; gap < n; gap++) {
            for (int i = 0; i < n - gap; i++) {
                int j = i + gap;
                if (s[i] == s[j]) {
                    dp[i][j] = (gap == 1) ? 0 : dp[i + 1][j - 1];
                } else {
                    dp[i][j] = 1 + min(dp[i][j - 1], dp[i + 1][j]);
                }
            }
        }
        return dp[0][n - 1];
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    string s;
    cin >> s;
    Solution sol;
    int ans = sol.minInsertions(s);
    cout << ans << '\n';
    return 0;
}
